local _M = {}

-- Secret key for token validation (in production, use a secure configuration)
local AUTH_SECRET = "your_secret_key_here"
local cjson = require "cjson.safe"
local ngx = ngx

-- Define role hierarchy and permissions
local role_permissions = {
    admin = {
        "/admin/dashboard",
        "/admin/users",
        "/admin/settings",
        "/api/v1/users",
        "/api/v1/reports",
        "/api/v1/config",
        "/api/v1/data"
    },
    editor = {
        "/api/v1/data",
        "/api/v1/reports",
        "/api/v1/content"
    },
    viewer = {
        "/api/v1/data",
        "/api/v1/reports"
    }
}

-- Endpoints that skip permission checks (public endpoints)
local public_endpoints = {
    "/health",
    "/status",
    "/login",
    "/register",
    "/public"
}

-- Helper: check if a URI matches any pattern in a list
local function uri_matches_any(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Helper: decode a base64url string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Helper: validate and decode a JWT-like token
local function decode_token(token)
    if not token or token == "" then
        return nil, "empty token"
    end

    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "invalid token format"
    end

    local header_raw = parts[1]
    local payload_raw = parts[2]
    local signature = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_raw .. "." .. payload_raw
    local expected_signature = ngx.encode_base64(ngx.hmac_sha1(AUTH_SECRET, signing_input))
    -- Normalize base64url
    expected_signature = expected_signature:gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature ~= expected_signature then
        return nil, "invalid token signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_raw)
    if not payload_json then
        return nil, "failed to decode token payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "failed to parse token JSON: " .. (err or "unknown error")
    end

    -- Check token expiration
    if payload.exp and payload.exp < ngx.time() then
        return nil, "token expired"
    end

    return payload, nil
end

-- Helper: extract Bearer token from Authorization header
local function extract_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil, "missing Authorization header"
    end

    local token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
    if not token then
        return nil, "invalid Authorization header format, expected 'Bearer <token>'"
    end

    return token, nil
end

-- Helper: check if user role has permission for the given URI
local function check_role_permission(role, uri)
    if not role or not role_permissions[role] then
        return false, "unknown role: " .. tostring(role)
    end

    local allowed_paths = role_permissions[role]
    for _, allowed_path in ipairs(allowed_paths) do
        -- Check if the request URI starts with or contains the allowed path
        if string.find(uri, allowed_path, 1, true) then
            return true, nil
        end
    end

    return false, "role '" .. role .. "' does not have permission for URI: " .. uri
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri

    -- Step 1: Check if the endpoint is public (skip all checks)
    if uri_matches_any(uri, public_endpoints) then
        ngx.log(ngx.INFO, "Public endpoint accessed: ", uri)
        return -- Allow access without authentication
    end

    -- Step 2: Check if the URI contains "/admin" or "/api" — these require permission checks
    local requires_permission_check = false
    if string.find(uri, "/admin", 1, true) or string.find(uri, "/api", 1, true) then
        requires_permission_check = true
    end

    -- If the URI does not contain /admin or /api, skip detailed permission checks
    -- but still require a valid authentication token
    -- Step 3: Extract and validate the authentication token
    local token, err = extract_token()
    if not token then
        ngx.log(ngx.WARN, "Authentication failed: ", err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = err
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    local payload, decode_err = decode_token(token)
    if not payload then
        ngx.log(ngx.WARN, "Token validation failed: ", decode_err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Invalid authentication token: " .. decode_err
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Extract user information from token payload
    local user_id = payload.sub or payload.user_id
    local user_role = payload.role
    local username = payload.username or "unknown"

    if not user_id then
        ngx.log(ngx.WARN, "Token missing user identifier")
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Token missing user identifier"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    if not user_role then
        ngx.log(ngx.WARN, "Token missing user role for user: ", user_id)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "forbidden",
            message = "Token missing user role"
        }))
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Set user info in request context for downstream use
    ngx.var.user_id = user_id
    ngx.req.set_header("X-User-ID", user_id)
    ngx.req.set_header("X-User-Role", user_role)
    ngx.req.set_header("X-Username", username)

    -- Step 5: If the endpoint requires permission checks (/admin or /api), verify role permissions
    if requires_permission_check then
        -- Additional check: /admin endpoints require admin role explicitly
        if string.find(uri, "/admin", 1, true) then
            if not string.match(user_role, "^admin$") then
                ngx.log(ngx.WARN, "Non-admin user '", username, "' (role: ", user_role, ") attempted to access admin endpoint: ", uri)
                ngx.status = ngx.HTTP_FORBIDDEN
                ngx.header["Content-Type"] = "application/json"
                ngx.say(cjson.encode({
                    error = "forbidden",
                    message = "Admin access required for this endpoint"
                }))
                return ngx.exit(ngx.HTTP_FORBIDDEN)
            end
        end

        -- Check role-based permissions for the specific URI
        local has_permission, perm_err = check_role_permission(user_role, uri)
        if not has_permission then
            ngx.log(ngx.WARN, "Permission denied for user '", username, "' (role: ", user_role, ") on URI: ", uri, " - ", perm_err)
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = "forbidden",
                message = "You do not have permission to access this resource",
                details = perm_err
            }))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end

        ngx.log(ngx.INFO, "Access granted for user '", username, "' (role: ", user_role, ") on URI: ", uri)
    else
        -- For non-admin/non-api endpoints, authentication alone is sufficient
        ngx.log(ngx.INFO, "Authenticated access granted for user '", username, "' on URI: ", uri, " (no role check required)")
    end

    -- Access granted — request proceeds to upstream
end

-- Rate limiting helper per user
function _M.rate_limit_by_user()
    local user_id = ngx.req.get_headers()["X-User-ID"]
    if not user_id then
        return -- No user context, skip rate limiting
    end

    local limit_count = 100 -- requests
    local limit_window = 60 -- seconds

    local shared_dict = ngx.shared.rate_limit
    if not shared_dict then
        ngx.log(ngx.ERR, "Shared dict 'rate_limit' not configured")
        return
    end

    local key = "rate:" .. user_id
    local current, err = shared_dict:incr(key, 1, 0, limit_window)

    if not current then
        ngx.log(ngx.ERR, "Rate limit incr failed: ", err)
        return
    end

    if current > limit_count then
        ngx.log(ngx.WARN, "Rate limit exceeded for user: ", user_id)
        ngx.status = 429
        ngx.header["Content-Type"] = "application/json"
        ngx.header["Retry-After"] = tostring(limit_window)
        ngx.say(cjson.encode({
            error = "too_many_requests",
            message = "Rate limit exceeded. Please try again later.",
            retry_after = limit_window
        }))
        return ngx.exit(429)
    end

    -- Set rate limit headers
    ngx.header["X-RateLimit-Limit"] = tostring(limit_count)
    ngx.header["X-RateLimit-Remaining"] = tostring(limit_count - current)
end

return _M